import{_ as t,o as a,c as o,au as d}from"./chunks/framework.Bpqx6pAq.js";const u=JSON.parse('{"title":"Base Editor","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/mixins/mixins.base-editor.md","filePath":"api/core/mixins/mixins.base-editor.md"}'),r={name:"api/core/mixins/mixins.base-editor.md"};function i(s,e,c,l,n,h){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="base-editor" tabindex="-1">Base Editor <a class="header-anchor" href="#base-editor" aria-label="Permalink to &quot;Base Editor&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <code>baseEditor</code> mixin provides the full lifecycle for form-based create/update editors. It handles schema and object loading, form binding, validation, service calls (create or patch), and perspective-aware data mapping.</p><p>The editor operates in one of two modes:</p><ul><li><strong><code>create</code></strong> — when no <code>objectId</code> prop is present; the form submits a <code>service.create()</code> call.</li><li><strong><code>update</code></strong> — when an <code>objectId</code> prop is present; the form submits a <code>service.patch()</code> call.</li></ul><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { service, objectProxy, schemaProxy, baseEditor } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@kalisio/kdk/core/client&#39;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> default</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  mixins: [service, objectProxy, schemaProxy, baseEditor],</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // ...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>This mixin requires the <a href="./mixins.service.html">Service</a>, <a href="./mixins.object-proxy.html">Object Proxy</a>, and <a href="./mixins.schema-proxy.html">Schema Proxy</a> mixins to be applied alongside it.</p></div><h2 id="emits" tabindex="-1">Emits <a class="header-anchor" href="#emits" aria-label="Permalink to &quot;Emits&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Event</th><th>Payload</th><th>Description</th></tr></thead><tbody><tr><td><code>applied</code></td><td><code>response</code></td><td>Emitted after the service call succeeds, with the service response as payload.</td></tr></tbody></table><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Prop</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>baseObject</code></td><td><code>Object</code></td><td><code>{}</code></td><td>Fallback object used when no service object is loaded. Useful for carrying hidden or internal properties into the submission.</td></tr><tr><td><code>baseQuery</code></td><td><code>Object</code></td><td><code>{}</code></td><td>Additional query parameters merged into every service call.</td></tr><tr><td><code>schemaName</code></td><td><code>String</code></td><td><code>undefined</code></td><td>Explicit schema resource name. Overrides the auto-derived name.</td></tr><tr><td><code>perspective</code></td><td><code>String</code></td><td><code>&#39;&#39;</code></td><td>When set, only the specified perspective of the object is loaded and patched.</td></tr><tr><td><code>perspectiveAsObject</code></td><td><code>Boolean</code></td><td><code>true</code></td><td>When <code>true</code> (default), the in-memory object holds the perspective data directly. When <code>false</code>, it holds the full structure <code>{ [perspective]: { ... } }</code>.</td></tr><tr><td><code>clearButton</code></td><td><code>String</code></td><td><code>&#39;&#39;</code></td><td>Label for the clear button, if exposed by the editor template.</td></tr><tr><td><code>resetButton</code></td><td><code>String</code></td><td><code>&#39;&#39;</code></td><td>Label for the reset button, if exposed by the editor template.</td></tr></tbody></table><h2 id="computed-properties" tabindex="-1">Computed Properties <a class="header-anchor" href="#computed-properties" aria-label="Permalink to &quot;Computed Properties&quot;">​</a></h2><h3 id="editortitle" tabindex="-1"><code>editorTitle</code> <a class="header-anchor" href="#editortitle" aria-label="Permalink to &quot;`editorTitle`&quot;">​</a></h3><p>Returns the internationalized title of the editor, derived from the loaded schema&#39;s <code>title</code> field. The object name is passed as an interpolation variable.</p><ul><li><strong>Returns:</strong> <code>string</code> — the translated schema title, or an empty string if no schema is loaded.</li></ul><h3 id="editormode" tabindex="-1"><code>editorMode</code> <a class="header-anchor" href="#editormode" aria-label="Permalink to &quot;`editorMode`&quot;">​</a></h3><p>Returns the current editor mode.</p><ul><li><strong>Returns:</strong> <code>&#39;update&#39;</code> if <code>objectId</code> is set, <code>&#39;create&#39;</code> otherwise.</li></ul><h3 id="applybutton" tabindex="-1"><code>applyButton</code> <a class="header-anchor" href="#applybutton" aria-label="Permalink to &quot;`applyButton`&quot;">​</a></h3><p>Returns the label for the submit button, localized.</p><ul><li><strong>Returns:</strong> <code>&#39;UPDATE&#39;</code> in update mode, <code>&#39;CREATE&#39;</code> in create mode.</li></ul><h2 id="data" tabindex="-1">Data <a class="header-anchor" href="#data" aria-label="Permalink to &quot;Data&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>isFormReady</code></td><td><code>Boolean</code></td><td><code>false</code></td><td>Set to <code>true</code> once the form component signals it is ready via <code>onFormReady()</code>.</td></tr><tr><td><code>applyInProgress</code></td><td><code>Boolean</code></td><td><code>false</code></td><td>Set to <code>true</code> while a service call is in-flight.</td></tr></tbody></table><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h2><h3 id="getbaseobject" tabindex="-1"><code>getBaseObject()</code> <a class="header-anchor" href="#getbaseobject" aria-label="Permalink to &quot;`getBaseObject()`&quot;">​</a></h3><p>Returns the object that will be used as the starting point for form submission. It merges the loaded service object (or <code>baseObject</code> prop as fallback) with perspective-aware data extraction.</p><ul><li><strong>Returns:</strong> <code>Object</code></li></ul><h3 id="getbasequery" tabindex="-1"><code>getBaseQuery()</code> <a class="header-anchor" href="#getbasequery" aria-label="Permalink to &quot;`getBaseQuery()`&quot;">​</a></h3><p>Returns the query object that will be sent alongside the service call. In update mode with a perspective, automatically adds <code>$select: [&#39;_id&#39;, perspective]</code>.</p><ul><li><strong>Returns:</strong> <code>Object</code></li></ul><h3 id="getschemaname" tabindex="-1"><code>getSchemaName()</code> <a class="header-anchor" href="#getschemaname" aria-label="Permalink to &quot;`getSchemaName()`&quot;">​</a></h3><p>Computes the schema resource name. Resolution order:</p><ol><li><code>schemaName</code> prop (explicit override)</li><li><code>this.$route.meta.schemaName</code> (route metadata)</li><li>Auto-derived: <code>&lt;service&gt;.&lt;create|update&gt;[-&lt;perspective&gt;]</code></li></ol><ul><li><strong>Returns:</strong> <code>string</code></li></ul><h3 id="onformreferencecreated-reference" tabindex="-1"><code>onFormReferenceCreated(reference)</code> <a class="header-anchor" href="#onformreferencecreated-reference" aria-label="Permalink to &quot;`onFormReferenceCreated(reference)`&quot;">​</a></h3><p>Stores a reference to the form component instance. Should be bound to the form&#39;s <code>ref</code> callback in the template.</p><ul><li><strong>Parameters:</strong><ul><li><code>reference</code> <em>(Object)</em>: The form component instance.</li></ul></li></ul><h3 id="onformready" tabindex="-1"><code>onFormReady()</code> <a class="header-anchor" href="#onformready" aria-label="Permalink to &quot;`onFormReady()`&quot;">​</a></h3><p>Called when the form component emits its ready event. Sets <code>isFormReady</code> to <code>true</code> and calls <code>fillEditor()</code>.</p><h3 id="filleditor" tabindex="-1"><code>fillEditor()</code> <a class="header-anchor" href="#filleditor" aria-label="Permalink to &quot;`fillEditor()`&quot;">​</a></h3><p>Fills the form with the currently loaded object&#39;s values. If a <code>perspective</code> is set, only the perspective data is passed to the form.</p><ul><li><strong>Throws:</strong> <code>Error</code> if called before the form is ready.</li></ul><h3 id="cleareditor" tabindex="-1"><code>clearEditor()</code> <a class="header-anchor" href="#cleareditor" aria-label="Permalink to &quot;`clearEditor()`&quot;">​</a></h3><p>Clears all form fields back to their default values.</p><ul><li><strong>Throws:</strong> <code>Error</code> if called before the form is ready.</li></ul><h3 id="reseteditor" tabindex="-1"><code>resetEditor()</code> <a class="header-anchor" href="#reseteditor" aria-label="Permalink to &quot;`resetEditor()`&quot;">​</a></h3><p>Resets the form to the currently loaded object&#39;s values (equivalent to calling <code>fillEditor()</code> again).</p><ul><li><strong>Throws:</strong> <code>Error</code> if called before the form is ready.</li></ul><h3 id="async-apply" tabindex="-1"><code>async apply()</code> <a class="header-anchor" href="#async-apply" aria-label="Permalink to &quot;`async apply()`&quot;">​</a></h3><p>Validates the form and, if valid, performs the service operation:</p><ul><li><strong><code>create</code> mode</strong>: calls <code>service.create(object, { query })</code>.</li><li><strong><code>update</code> mode</strong>: calls <code>service.patch(objectId, data, { query })</code>, where <code>data</code> is perspective-aware.</li></ul><p>After a successful call, calls <code>form.submitted(response)</code> and emits <code>applied</code>.</p><ul><li><strong>Returns:</strong> <code>boolean</code> — <code>true</code> on success, <code>false</code> if validation failed or a service error occurred.</li></ul><h3 id="async-refresh" tabindex="-1"><code>async refresh()</code> <a class="header-anchor" href="#async-refresh" aria-label="Permalink to &quot;`async refresh()`&quot;">​</a></h3><p>Reloads the schema and object in parallel, then fills the editor if the form is already ready.</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Typical usage in mounted()</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">await</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">refresh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><code>refresh()</code> resets <code>this.form</code> to <code>null</code> before loading so that a form re-render triggered by reactive data changes starts from a clean state.</p></div>',58)])])}const m=t(r,[["render",i]]);export{u as __pageData,m as default};
